// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';

// --- COMPONENT CHÍNH ---
function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  // --- STATE QUẢN LÝ DỮ LIỆU ---
  const [farmDetails, setFarmDetails] = useState(null);
  const [activities, setActivities] = useState([]);
  const [speciesOptions, setSpeciesOptions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State cho form thêm bản ghi mới
  const [formData, setFormData] = useState({
    speciesName: '',
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  // --- LOGIC LẤY DỮ LIỆU ---
  const fetchData = useCallback(async () => {
    if (!farmId || !token) {
      setError('Thiếu thông tin xác thực hoặc ID cơ sở.');
      setLoading(false);
      return;
    }

    setLoading(true);
    setError('');
    setMessage('');

    try {
      const farmRes = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const details = farmRes.data;
      setFarmDetails(details);

      let availableSpecies = [];
      if (details.loaiDongVatRung && Array.isArray(details.loaiDongVatRung)) {
        availableSpecies = details.loaiDongVatRung.map(s => s.tenLamSan).filter(Boolean);
      } else if (typeof details.tenLamSan === 'string') {
        availableSpecies.push(details.tenLamSan);
      }
      setSpeciesOptions(availableSpecies);

      const activitiesRes = await axios.get(`http://localhost:10000/api/wood-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(activitiesRes.data);

      setFormData(prev => ({
        ...prev,
        speciesName: availableSpecies[0] || '',
      }));

    } catch (err) {
      console.error('Lỗi khi tải dữ liệu:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Không thể tải dữ liệu. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  }, [farmId, token]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);


  // --- CÁC HÀM XỬ LÝ SỰ KIỆN ---
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseInt(value, 10) || 0 : value,
    }));
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');

    try {
      const dataToSend = { ...formData, farm: farmId };
      const res = await axios.post(`http://localhost:10000/api/wood-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });

      setActivities(prev => [...prev, res.data]);
      setMessage('Thêm bản ghi thành công!');
      setFormData(prev => ({
        ...prev,
        date: '',
        quantity: 0,
        unit: '',
        type: '',
        reason: '',
        source: '',
        destination: '',
        verifiedBy: '',
      }));
    } catch (err) {
      console.error('Lỗi khi thêm bản ghi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Thêm bản ghi thất bại.');
    }
  };

  const handleDeleteActivity = async (activityId) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa bản ghi này?')) {
      try {
        await axios.delete(`http://localhost:10000/api/wood-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setActivities(prev => prev.filter(act => act._id !== activityId));
        setMessage('Xóa bản ghi thành công.');
      } catch (err) {
        console.error('Lỗi khi xóa bản ghi:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Xóa bản ghi thất bại.');
      }
    }
  };


  // --- HIỂN THỊ GIAO DIỆN (RENDER) ---
  if (loading) {
    return <div className="form-container"><p>Đang tải dữ liệu...</p></div>;
  }

  if (error && !farmDetails) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lỗi: {error}</p>
        <button onClick={() => navigate('/admin/woods')}>Quay lại danh sách</button>
      </div>
    );
  }
  
  return (
    <div className="form-container">
       <style>{`
        .farm-details-section {
          padding: 15px;
          border: 1px solid #ddd;
          border-radius: 8px;
          margin-bottom: 25px;
          background-color: #f9f9f9;
        }
        .details-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
          gap: 15px;
        }
        .detail-item strong {
          display: block;
          color: #555;
          margin-bottom: 5px;
        }
        .detail-item p {
          margin: 0;
          font-size: 1rem;
        }
       `}</style>
      
      <h2>👁️ Nhật ký hoạt động gỗ của cơ sở: {farmDetails?.tenCoSo || 'N/A'}</h2>
      
      {/* ====== PHẦN HIỂN THỊ THÔNG TIN MỚI ĐƯỢC THÊM ====== */}
      <section className="farm-details-section">
        <h3>Thông tin chi tiết cơ sở</h3>
        <div className="details-grid">
          <div className="detail-item">
            <strong>Địa chỉ:</strong>
            <p>{farmDetails?.diaChiCoSo || 'N/A'}</p>
          </div>
          <div className="detail-item">
            <strong>Loại hình chế biến gỗ:</strong>
            <p>{farmDetails?.loaiHinhCheBienGo || 'N/A'}</p>
          </div>
          <div className="detail-item">
            <strong>Nguồn gốc gỗ:</strong>
            <p>{farmDetails?.nguonGocGo || 'N/A'}</p>
          </div>
        </div>
      </section>
      {/* ====== KẾT THÚC PHẦN THÊM MỚI ====== */}


      {/* --- FORM THÊM BẢN GHI MỚI --- */}
      <h3>Thêm bản ghi nhập/xuất mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          <div className="form-group">
            <label>Tên lâm sản:</label>
            <select name="speciesName" value={formData.speciesName} onChange={handleFormChange} required>
              <option value="">-- Chọn lâm sản --</option>
              {speciesOptions.map((species, index) => (
                <option key={index} value={species}>{species}</option>
              ))}
            </select>
          </div>

          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input type="date" name="date" value={formData.date} onChange={handleFormChange} required />
          </div>

          <div className="form-group">
            <label>Loại giao dịch:</label>
            <select name="type" value={formData.type} onChange={handleFormChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="import">Nhập</option>
              <option value="export">Xuất</option>
            </select>
          </div>

          <div className="form-group">
            <label>Số lượng:</label>
            <input type="number" name="quantity" value={formData.quantity} onChange={handleFormChange} min="0" required />
          </div>

          <div className="form-group">
            <label>Đơn vị:</label>
            <input type="text" name="unit" value={formData.unit} onChange={handleFormChange} required />
          </div>

          <div className="form-group">
            <label>Lý do:</label>
            <input type="text" name="reason" value={formData.reason} onChange={handleFormChange} />
          </div>

          {formData.type === 'import' && (
            <div className="form-group">
              <label>Nguồn gốc:</label>
              <input type="text" name="source" value={formData.source} onChange={handleFormChange} required/>
            </div>
          )}

          {formData.type === 'export' && (
            <div className="form-group">
              <label>Nơi đến:</label>
              <input type="text" name="destination" value={formData.destination} onChange={handleFormChange} />
            </div>
          )}
           <div className="form-group">
            <label>Người xác nhận:</label>
            <input type="text" name="verifiedBy" value={formData.verifiedBy} onChange={handleFormChange} />
          </div>
        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      {/* --- BẢNG LỊCH SỬ HOẠT ĐỘNG --- */}
      <h3>Lịch sử nhập/xuất gỗ:</h3>
      <div className="activity-list-container">
        {activities.length === 0 ? (
          <p>Chưa có bản ghi nào.</p>
        ) : (
          <table className="activity-table">
            <thead>
              <tr>
                <th>STT</th>
                <th>Ngày</th>
                <th>Loài gỗ</th>
                <th>Loại</th>
                <th>Số lượng</th>
                <th>Đơn vị</th>
                <th>Lý do</th>
                <th>Nguồn/Đích</th>
                <th>Người xác nhận</th>
                {role === 'admin' && <th>Hành động</th>}
              </tr>
            </thead>
            <tbody>
              {activities.map((activity, index) => (
                <tr key={activity._id}>
                  <td>{index + 1}</td>
                  <td>{new Date(activity.date).toLocaleDateString()}</td>
                  <td>{activity.speciesName}</td>
                  <td>{activity.type === 'import' ? 'Nhập' : 'Xuất'}</td>
                  <td>{activity.quantity}</td>
                  <td>{activity.unit}</td>
                  <td>{activity.reason || 'N/A'}</td>
                  <td>{activity.type === 'import' ? activity.source : activity.destination || 'N/A'}</td>
                  <td>{activity.verifiedBy || 'N/A'}</td>
                  {role === 'admin' && (
                    <td>
                      <button onClick={() => handleDeleteActivity(activity._id)} className="delete-button">Xóa</button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
      
      <div className="detail-actions">
        <button onClick={() => navigate('/admin/woods')} className="cancel-button">Quay lại danh sách</button>
      </div>
    </div>
  );
}

export default WoodDetail;
